#include <iostream>
#include <vector>

int main() {
    int N;
    std::cin >> N;

    // dp[i] = number of ways to form sum i using digits 1..9 (any length)
    std::vector<long long> dp(N + 1, 0);
    dp[0] = 1; // empty sequence

    for (int i = 1; i <= N; ++i) {
        for (int d = 1; d <= 9; ++d) {
            if (i >= d) {
                dp[i] += dp[i - d];
            }
        }
    }

    std::cout << dp[N] << std::endl;

    return 0;
}
